static bool
in_ranges(uint32_t cp, const struct unicode_range *ranges, int count)
{
	int lo = 0, hi = count - 1;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp < ranges[mid].start)
			hi = mid - 1;
		else if(cp > ranges[mid].end)
			lo = mid + 1;
		else
			return true;
	}
	return false;
}

static uint32_t
lookup_pair(uint32_t cp, const struct unicode_pair *table, int count)
{
	int lo = 0, hi = count - 1;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp < table[mid].from)
			hi = mid - 1;
		else if(cp > table[mid].from)
			lo = mid + 1;
		else
			return table[mid].to;
	}
	return cp;
}

