int
unicode_canonical_class(uint32_t cp)
{
	int lo = 0, hi = 933;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp < ccc_table[mid].cp)
			hi = mid - 1;
		else if(cp > ccc_table[mid].cp)
			lo = mid + 1;
		else
			return ccc_table[mid].ccc;
	}
	return 0;
}

