#define COMP_TABLE_SIZE 961

/* Canonical decomposition lookup */
static int
lookup_decomp(uint32_t cp, uint32_t *out, int outmax)
{
	int lo = 0, hi = DECOMP_TABLE_SIZE - 1;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp < decomp_table[mid].cp)
			hi = mid - 1;
		else if(cp > decomp_table[mid].cp)
			lo = mid + 1;
		else
		{
			int len = decomp_table[mid].len;
			if(len > outmax)
				return -1;
			for(int i = 0; i < len; i++)
				out[i] = decomp_table[mid].decomp[i];
			return len;
		}
	}
	return 0; /* no decomposition */
}

/* Hangul constants */
#define HANGUL_SBASE  0xAC00
#define HANGUL_LBASE  0x1100
#define HANGUL_VBASE  0x1161
#define HANGUL_TBASE  0x11A7
#define HANGUL_LCOUNT 19
#define HANGUL_VCOUNT 21
#define HANGUL_TCOUNT 28
#define HANGUL_NCOUNT (HANGUL_VCOUNT * HANGUL_TCOUNT)
#define HANGUL_SCOUNT (HANGUL_LCOUNT * HANGUL_NCOUNT)

/* Full recursive canonical decomposition into buf. Returns length or -1. */
static int
full_decomp(uint32_t cp, uint32_t *buf, int bufmax)
{
	/* Hangul algorithmic decomposition */
	if(cp >= HANGUL_SBASE && cp < HANGUL_SBASE + HANGUL_SCOUNT)
	{
		int sindex = cp - HANGUL_SBASE;
		int l = HANGUL_LBASE + sindex / HANGUL_NCOUNT;
		int v = HANGUL_VBASE + (sindex % HANGUL_NCOUNT) / HANGUL_TCOUNT;
		int t = HANGUL_TBASE + sindex % HANGUL_TCOUNT;
		int len = (t == HANGUL_TBASE) ? 2 : 3;
		if(len > bufmax)
			return -1;
		buf[0] = l;
		buf[1] = v;
		if(t != HANGUL_TBASE)
			buf[2] = t;
		return len;
	}

	uint32_t tmp[4];
	int dlen = lookup_decomp(cp, tmp, 4);
	if(dlen <= 0)
	{
		if(bufmax < 1)
			return -1;
		buf[0] = cp;
		return 1;
	}

	/* Recursively decompose each part */
	int total = 0;
	for(int i = 0; i < dlen; i++)
	{
		int n = full_decomp(tmp[i], buf + total, bufmax - total);
		if(n < 0)
			return -1;
		total += n;
	}
	return total;
}

/* Canonical composition lookup */
static uint32_t
lookup_comp(uint32_t cp1, uint32_t cp2)
{
	/* Hangul algorithmic composition */
	if(cp1 >= HANGUL_LBASE && cp1 < HANGUL_LBASE + HANGUL_LCOUNT
	   && cp2 >= HANGUL_VBASE && cp2 < HANGUL_VBASE + HANGUL_VCOUNT)
	{
		return HANGUL_SBASE + ((cp1 - HANGUL_LBASE) * HANGUL_VCOUNT + (cp2 - HANGUL_VBASE)) * HANGUL_TCOUNT;
	}
	if(cp1 >= HANGUL_SBASE && cp1 < HANGUL_SBASE + HANGUL_SCOUNT
	   && ((cp1 - HANGUL_SBASE) % HANGUL_TCOUNT) == 0
	   && cp2 > HANGUL_TBASE && cp2 < HANGUL_TBASE + HANGUL_TCOUNT)
	{
		return cp1 + (cp2 - HANGUL_TBASE);
	}

	/* Binary search the composition table */
	int lo = 0, hi = COMP_TABLE_SIZE - 1;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp1 < comp_table[mid].cp1 ||
		   (cp1 == comp_table[mid].cp1 && cp2 < comp_table[mid].cp2))
			hi = mid - 1;
		else if(cp1 > comp_table[mid].cp1 ||
		        (cp1 == comp_table[mid].cp1 && cp2 > comp_table[mid].cp2))
			lo = mid + 1;
		else
			return comp_table[mid].composed;
	}
	return 0; /* no composition */
}

int
unicode_nfc(const uint32_t *input, int inlen, uint32_t *output, int outmax)
{
	/* Step 1: Canonical decomposition */
	uint32_t decomposed[512];
	int dlen = 0;
	for(int i = 0; i < inlen; i++)
	{
		int n = full_decomp(input[i], decomposed + dlen, 512 - dlen);
		if(n < 0)
			return -1;
		dlen += n;
	}

	/* Step 2: Canonical ordering (sort combining marks by CCC) */
	for(int i = 1; i < dlen; i++)
	{
		int ccc = unicode_canonical_class(decomposed[i]);
		if(ccc == 0)
			continue;
		int j = i;
		while(j > 0)
		{
			int prev_ccc = unicode_canonical_class(decomposed[j - 1]);
			if(prev_ccc == 0 || prev_ccc <= ccc)
				break;
			uint32_t tmp = decomposed[j];
			decomposed[j] = decomposed[j - 1];
			decomposed[j - 1] = tmp;
			j--;
		}
	}

	/* Step 3: Canonical composition */
	if(dlen == 0)
	{
		return 0;
	}

	uint32_t composed[512];
	int clen = 0;
	composed[clen++] = decomposed[0];

	for(int i = 1; i < dlen; i++)
	{
		int last_starter = -1;
		/* Find the last starter in composed buffer */
		for(int k = clen - 1; k >= 0; k--)
		{
			if(unicode_canonical_class(composed[k]) == 0)
			{
				last_starter = k;
				break;
			}
		}

		int cur_ccc = unicode_canonical_class(decomposed[i]);

		/* Check if we can compose with the last starter */
		if(last_starter >= 0)
		{
			/* Blocked check: there must not be a character with CCC >= cur_ccc
			 * between the last starter and current position (unless cur_ccc == 0) */
			bool blocked = false;
			if(cur_ccc != 0)
			{
				for(int k = last_starter + 1; k < clen; k++)
				{
					int between_ccc = unicode_canonical_class(composed[k]);
					if(between_ccc >= cur_ccc)
					{
						blocked = true;
						break;
					}
				}
			}
			else if(last_starter < clen - 1)
			{
				blocked = true;
			}

			if(!blocked)
			{
				uint32_t comp = lookup_comp(composed[last_starter], decomposed[i]);
				if(comp != 0)
				{
					composed[last_starter] = comp;
					continue;
				}
			}
		}

		if(clen >= 512)
			return -1;
		composed[clen++] = decomposed[i];
	}

	if(clen > outmax)
		return -1;
	for(int i = 0; i < clen; i++)
		output[i] = composed[i];
	return clen;
}

