int
unicode_script(uint32_t cp)
{
	int lo = 0, hi = 978;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp < script_table[mid].start)
			hi = mid - 1;
		else if(cp > script_table[mid].end)
			lo = mid + 1;
		else
			return script_table[mid].script_id;
	}
	return SCRIPT_COMMON;
}

int
unicode_bidi_class(uint32_t cp)
{
	/* Simplified bidi class lookup using ranges from UnicodeData.txt */
	/* For the RFC 5893 check we only care about L, R, AL, AN, EN, ES, CS, ET, ON, BN, NSM */
	/* ASCII fast path */
	if(cp < 0x0080)
		return BIDI_L;
	/* Hebrew */
	if(cp >= 0x0590 && cp <= 0x05FF)
		return BIDI_R;
	/* Arabic */
	if(cp >= 0x0600 && cp <= 0x06FF)
		return BIDI_AL;
	/* Default to L for most scripts */
	return BIDI_L;
}

bool
unicode_check_bidi(const uint32_t *cps, int len)
{
	if(len == 0)
		return true;

	int first_class = unicode_bidi_class(cps[0]);

	/* If label starts with L, it's an LTR label — all chars must be
	 * L, EN, ES, CS, ET, ON, BN, NSM per RFC 5893 Rule 1 */
	if(first_class == BIDI_L)
	{
		for(int i = 0; i < len; i++)
		{
			int bc = unicode_bidi_class(cps[i]);
			if(bc != BIDI_L && bc != BIDI_EN && bc != BIDI_ES &&
			   bc != BIDI_CS && bc != BIDI_ET && bc != BIDI_ON &&
			   bc != BIDI_BN && bc != BIDI_NSM)
				return false;
		}
		return true;
	}

	/* If label starts with R or AL, it's an RTL label — RFC 5893 Rules 2-6 */
	if(first_class == BIDI_R || first_class == BIDI_AL)
	{
		/* Rule 2: only R, AL, AN, EN, ES, CS, ET, ON, BN, NSM allowed */
		for(int i = 0; i < len; i++)
		{
			int bc = unicode_bidi_class(cps[i]);
			if(bc != BIDI_R && bc != BIDI_AL && bc != BIDI_AN &&
			   bc != BIDI_EN && bc != BIDI_ES && bc != BIDI_CS &&
			   bc != BIDI_ET && bc != BIDI_ON && bc != BIDI_BN &&
			   bc != BIDI_NSM)
				return false;
		}

		/* Rule 3: last non-NSM char must be R or AL or AN or EN */
		int last_bc = -1;
		for(int i = len - 1; i >= 0; i--)
		{
			last_bc = unicode_bidi_class(cps[i]);
			if(last_bc != BIDI_NSM)
				break;
		}
		if(last_bc != BIDI_R && last_bc != BIDI_AL &&
		   last_bc != BIDI_AN && last_bc != BIDI_EN)
			return false;

		return true;
	}

	/* Label doesn't start with L, R, or AL — reject */
	return false;
}

