#define CONFUSABLE_TABLE_SIZE 6355

int
unicode_confusable_map(uint32_t cp, uint32_t *out, int outmax)
{
	int lo = 0, hi = CONFUSABLE_TABLE_SIZE - 1;
	while(lo <= hi)
	{
		int mid = (lo + hi) / 2;
		if(cp < confusable_table[mid].from)
			hi = mid - 1;
		else if(cp > confusable_table[mid].from)
			lo = mid + 1;
		else
		{
			int len = confusable_table[mid].len;
			if(len > outmax)
				return -1;
			for(int i = 0; i < len; i++)
				out[i] = confusable_table[mid].to[i];
			return len;
		}
	}
	return 0;
}

/* NFD normalization — canonical decomposition only, no recomposition.
 * Used internally by unicode_skeleton(). */
static int
unicode_nfd(const uint32_t *input, int inlen, uint32_t *output, int outmax)
{
	int dlen = 0;
	for(int i = 0; i < inlen; i++)
	{
		int n = full_decomp(input[i], output + dlen, outmax - dlen);
		if(n < 0)
			return -1;
		dlen += n;
	}

	/* Canonical ordering */
	for(int i = 1; i < dlen; i++)
	{
		int ccc = unicode_canonical_class(output[i]);
		if(ccc == 0)
			continue;
		int j = i;
		while(j > 0)
		{
			int prev_ccc = unicode_canonical_class(output[j - 1]);
			if(prev_ccc == 0 || prev_ccc <= ccc)
				break;
			uint32_t tmp = output[j];
			output[j] = output[j - 1];
			output[j - 1] = tmp;
			j--;
		}
	}
	return dlen;
}

int
unicode_skeleton(const uint32_t *input, int inlen, uint32_t *output, int outmax)
{
	uint32_t buf1[512], buf2[512];

	/* Step 1: NFD */
	int len = unicode_nfd(input, inlen, buf1, 512);
	if(len < 0)
		return -1;

	/* Step 2: Strip default-ignorable codepoints */
	int stripped = 0;
	for(int i = 0; i < len; i++)
	{
		if(!unicode_is_default_ignorable(buf1[i]))
			buf2[stripped++] = buf1[i];
	}

	/* Step 3: Apply confusable mappings */
	int mapped = 0;
	for(int i = 0; i < stripped; i++)
	{
		uint32_t tmp[4];
		int n = unicode_confusable_map(buf2[i], tmp, 4);
		if(n > 0)
		{
			if(mapped + n > 512)
				return -1;
			for(int j = 0; j < n; j++)
				buf1[mapped++] = tmp[j];
		}
		else
		{
			if(mapped >= 512)
				return -1;
			buf1[mapped++] = buf2[i];
		}
	}

	/* Step 4: NFD again */
	return unicode_nfd(buf1, mapped, output, outmax);
}

int
precis_prepare_nick(const char *input, uint32_t *output, int outmax)
{
	const unsigned char *p = (const unsigned char *)input;
	uint32_t cps[128];
	int cplen = 0;

	/* Decode UTF-8 */
	while(*p && cplen < 128)
	{
		uint32_t cp;
		if(utf8_decode(&p, &cp) < 0)
			return -1;
		cps[cplen++] = cp;
	}
	if(*p) /* too long */
		return -1;

	/* Width mapping */
	for(int i = 0; i < cplen; i++)
		cps[i] = unicode_width_map(cps[i]);

	/* NFC normalization */
	uint32_t nfc_buf[128];
	int nfc_len = unicode_nfc(cps, cplen, nfc_buf, 128);
	if(nfc_len < 0)
		return -1;

	/* Category check: Letter, Mark, Digit only (plus ASCII IRC specials handled by caller) */
	for(int i = 0; i < nfc_len; i++)
	{
		uint32_t cp = nfc_buf[i];
		if(cp < 0x80)
			continue; /* ASCII chars validated by caller */
		if(!unicode_is_letter(cp) && !unicode_is_mark(cp) && !unicode_is_digit(cp))
			return -1;
	}

	/* Case fold */
	for(int i = 0; i < nfc_len; i++)
		nfc_buf[i] = unicode_casefold(nfc_buf[i]);

	/* Bidi check */
	if(!unicode_check_bidi(nfc_buf, nfc_len))
		return -1;

	if(nfc_len > outmax)
		return -1;
	for(int i = 0; i < nfc_len; i++)
		output[i] = nfc_buf[i];
	return nfc_len;
}
